#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<pair<long long, int>> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i].first;
    for(int i = 0; i < n; i++) nums[i].second = i;
    sort(nums.begin(), nums.end());
    vector<int> rank_map(n);
    int rank = 1;
    for(int i = 0; i < n; i++){
        if(i > 0 && nums[i].first != nums[i-1].first) rank = i + 1;
        rank_map[nums[i].second] = rank;
    }
    cout << n << '\n';
    for(int i = 0; i < n; i++) cout << rank_map[i] << ' ';
    return 0;
}
